import { AsyncStorage } from 'react-native';
import cryptoJs from 'crypto-js';

// Import encryption key from config file
const ENCRYPTION_KEY = require('./config').ENCRYPTION_KEY;

function encryptData(data) {
  const encrypted = cryptoJs.AES.encrypt(JSON.stringify(data), ENCRYPTION_KEY).toString();
  return encrypted;
}

function decryptData(encryptedData) {
  try {
    const decrypted = cryptoJs.AES.decrypt(encryptedData, ENCRYPTION_KEY).toString(cryptoJs.enc.Utf8);
    return JSON.parse(decrypted);
  } catch (error) {
    console.error('Error decrypting data:', error);
    return null;
  }
}

function saveEncryptedData(key, data) {
  const encrypted = encryptData(data);
  AsyncStorage.setItem(key, encrypted);
}

function loadEncryptedData(key) {
  const encryptedData = AsyncStorage.getItem(key);
  if (encryptedData !== null) {
    return decryptData(encryptedData);
  } else {
    console.error('No data found for key:', key);
    return null;
  }
}